Code.Terraform:
```hcl
resource "azurerm_cosmosdb_account" "<example_resource_name>" {
  name                          = "<example_resource_name>"
  location                      = "<example_resource_id>"
  resource_group_name           = "<example_resource_id>"
  offer_type                    = "Standard"
  public_network_access_enabled = false  # Critical: disables public network access

  consistency_policy {
    consistency_level = "Session"
  }

  geo_location {
    location          = "eastus"
    failover_priority = 0
  }
}
```
